// Parse Telegram getUpdates response and extract /start messages
const response = $input.item.json;
const updates = response.result || [];

const startMessages = [];
let maxUpdateId = null;

for (const update of updates) {
  if (maxUpdateId === null || update.update_id > maxUpdateId) {
    maxUpdateId = update.update_id;
  }
  const msg = update.message;
  if (msg && msg.text === '/start') {
    startMessages.push({
      json: {
        has_start: true,
        update_id: update.update_id,
        max_update_id: maxUpdateId,
        chat_id: String(msg.chat.id),
        first_name: msg.from?.first_name || 'User',
        username: msg.from?.username || '',
        text: msg.text
      }
    });
  }
}

// No /start messages — return sentinel so flow terminates cleanly
if (startMessages.length === 0) {
  return [{ json: { has_start: false, max_update_id: maxUpdateId, chat_id: null } }];
}

// Attach max_update_id to all items for acknowledge step
return startMessages.map(item => ({
  json: { ...item.json, max_update_id: maxUpdateId }
}));
